    fun all(): List<ExerciseEntity> {
        val now = Instant.now().toString()
        return catalog.map { c ->
            ExerciseEntity(
                name = c.name,
                muscleGroup = c.muscle.name,
                secondaryMuscles = "",
                equipment = c.equipment.name,
                instructions = "",
                isCustom = false,
                imagePath = c.image,
                effectivenessTier = c.tier,
                createdAt = now
            )
        }
    }
